Classify this social media comment.

comment: {{ $json.comment_text }}
platform: {{ $json.platform }}
post_context: "Daily Christian devotional — scripture-based, encouraging, non-denominational"

Return JSON with: classification, severity (mild/moderate/severe), reason, escalate (true/false), escalation_type

parameters.jsCode:
const src = $('📥 Simulate / Load New Comments').first().json;
const out = $('🏷️ Comment Classifier').first().json.output || {};
const cls = String(out.classification || '').toUpperCase();
const crisis = cls === 'CRISIS' || out.escalate === true;
const story_safe =
  !crisis &&
  ['SUPPORTIVE', 'TESTIMONY', 'QUESTION_SIMPLE', 'QUESTION_THEOLOGY', 'PRAYER_REQUEST'].includes(cls) &&
  !['severe'].includes(String(out.severity || '').toLowerCase());
return [
  {
    json: {
      platform: src.platform,
      platform_post_id: src.post_id,
      platform_comment_id: src.comment_id,
      comment_excerpt: String(src.comment_text || '').slice(0, 500),
      classification: out.classification,
      severity: out.severity,
      story_safe,
      status: crisis ? 'escalated' : 'unused',
    },
  },
];

